def factorial(n: int) -> int:
    """Return n! for non-negative n."""
    if n <= 1:
        return 1
    return n * factorial(n - 1)

# List comprehension
squares = [x ** 2 for x in range(10)]
print(squares)  # [0, 1, 4, 9, ...]
